@register.simple_tag
def brand_icon(icon_name, color='#000', size=22):
    svg = BRAND_SVGS.get(icon_name, '')
    if not svg:
        return mark_safe(f'<i class="bi bi-{icon_name}" style="color:{color};font-size:{size}px;"></i>')
    svg = svg.replace('COLOR', color).replace('width="22"', f'width="{size}"').replace('height="22"', f'height="{size}"')
    return mark_safe(svg)
